/**
 * PageListFlat Component - Display pages in flat list view
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { Edit, Folder } from 'lucide-react';
import Link from 'next/link';

interface Page {
  id: string;
  title: string;
  slug: string;
  language: string;
  status: string;
  isDefaultLang: boolean;
  updatedAt: string;
  pageGroupName?: string;
}

interface PageListFlatProps {
  onAddTranslation?: (pageId: string) => void;
}

export function PageListFlat({ onAddTranslation }: PageListFlatProps) {
  const [pages, setPages] = useState<Page[]>([]);
  const [loading, setLoading] = useState(true);
  const [sortBy, setSortBy] = useState<'name' | 'language' | 'status' | 'updated'>('name');
  const [filterLanguage, setFilterLanguage] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<string>('all');

  useEffect(() => {
    fetchPages();
  }, []);

  const fetchPages = async () => {
    try {
      const res = await fetch('/api/admin/pages/grouped');
      const result = await res.json();
      
      if (result.success) {
        // تبدیل گروهها به لیست flat
        const flatPages: Page[] = [];
        
        result.data.groups.forEach((group: any) => {
          group.pages.forEach((page: any) => {
            flatPages.push({
              ...page,
              pageGroupName: group.name
            });
          });
        });
        
        // اضافه کردن صفحات بدون گروه
        result.data.ungroupedPages.forEach((page: any) => {
          flatPages.push({
            ...page,
            pageGroupName: undefined
          });
        });
        
        setPages(flatPages);
      }
    } catch (error) {
      console.error('Error fetching pages:', error);
    } finally {
      setLoading(false);
    }
  };

  const getLanguageFlag = (lang: string) => {
    const flags: Record<string, string> = {
      en: '🇺🇸',
      ar: '🇸🇦',
      fr: '🇫🇷',
      de: '🇩🇪',
      es: '🇪🇸'
    };
    return flags[lang] || '🌐';
  };

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      published: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200',
      draft: 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200',
      archived: 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'
    };
    return (
      <span className={`px-2 py-1 text-xs rounded ${colors[status] || colors.draft}`}>
        {status}
      </span>
    );
  };

  // فیلتر و sort
  const filteredPages = pages
    .filter(page => {
      if (filterLanguage !== 'all' && page.language !== filterLanguage) return false;
      if (filterStatus !== 'all' && page.status !== filterStatus) return false;
      return true;
    })
    .sort((a, b) => {
      switch (sortBy) {
        case 'name':
          return a.title.localeCompare(b.title);
        case 'language':
          return a.language.localeCompare(b.language);
        case 'status':
          return a.status.localeCompare(b.status);
        case 'updated':
          return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
        default:
          return 0;
      }
    });

  // استخراج زبانها و statusها برای فیلتر
  const languages = Array.from(new Set(pages.map(p => p.language)));
  const statuses = Array.from(new Set(pages.map(p => p.status)));

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="text-gray-500">Loading pages...</div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Filters & Sort */}
      <div className="flex flex-wrap gap-4 items-center bg-white dark:bg-slate-800 p-4 rounded-lg border dark:border-slate-700">
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Sort by:</label>
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as any)}
            className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-slate-700 text-gray-900 dark:text-white"
          >
            <option value="name">Name</option>
            <option value="language">Language</option>
            <option value="status">Status</option>
            <option value="updated">Last Updated</option>
          </select>
        </div>

        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Language:</label>
          <select
            value={filterLanguage}
            onChange={(e) => setFilterLanguage(e.target.value)}
            className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-slate-700 text-gray-900 dark:text-white"
          >
            <option value="all">All</option>
            {languages.map(lang => (
              <option key={lang} value={lang}>{lang.toUpperCase()}</option>
            ))}
          </select>
        </div>

        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Status:</label>
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-slate-700 text-gray-900 dark:text-white"
          >
            <option value="all">All</option>
            {statuses.map(status => (
              <option key={status} value={status}>{status}</option>
            ))}
          </select>
        </div>

        <div className="ml-auto text-sm text-gray-500 dark:text-gray-400">
          {filteredPages.length} page{filteredPages.length !== 1 ? 's' : ''}
        </div>
      </div>

      {/* Pages List */}
      <div className="bg-white dark:bg-slate-800 rounded-lg border dark:border-slate-700 overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-50 dark:bg-slate-700 border-b dark:border-slate-600">
            <tr>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Page
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Language
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Group
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Status
              </th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Updated
              </th>
              <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200 dark:divide-slate-700">
            {filteredPages.map(page => (
              <tr key={page.id} className="hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors">
                <td className="px-4 py-3">
                  <div className="flex items-center gap-2">
                    <span className="text-xl">{getLanguageFlag(page.language)}</span>
                    <div>
                      <div className="font-medium text-gray-900 dark:text-white">{page.title}</div>
                      <div className="text-sm text-gray-500 dark:text-gray-400">{page.slug}</div>
                    </div>
                  </div>
                </td>
                <td className="px-4 py-3">
                  <div className="flex items-center gap-2">
                    <span className="font-medium text-gray-900 dark:text-white">
                      {page.language.toUpperCase()}
                    </span>
                    {page.isDefaultLang && (
                      <span className="text-xs bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200 px-2 py-0.5 rounded">
                        Default
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-4 py-3">
                  {page.pageGroupName ? (
                    <div className="flex items-center gap-1 text-sm text-gray-600 dark:text-gray-400">
                      <Folder size={14} />
                      {page.pageGroupName}
                    </div>
                  ) : (
                    <span className="text-sm text-gray-400 dark:text-gray-500">—</span>
                  )}
                </td>
                <td className="px-4 py-3">
                  {getStatusBadge(page.status)}
                </td>
                <td className="px-4 py-3 text-sm text-gray-500 dark:text-gray-400">
                  {new Date(page.updatedAt).toLocaleDateString()}
                </td>
                <td className="px-4 py-3 text-right">
                  <Link
                    href={`/admin/pages/${page.id}/edit`}
                    className="inline-flex items-center gap-1 px-3 py-1.5 text-sm border border-gray-300 dark:border-gray-600 rounded hover:bg-gray-100 dark:hover:bg-slate-600 transition-colors"
                  >
                    <Edit size={14} />
                    Edit
                  </Link>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {filteredPages.length === 0 && (
          <div className="text-center py-12 text-gray-500 dark:text-gray-400">
            No pages found matching your filters.
          </div>
        )}
      </div>
    </div>
  );
}
